import axios from 'axios'
const request = axios.create({
  baseURL: process.env.BASE_API,
  timeout: 120000,
  withCredentials: true
})
request.interceptors.request.use(
  config => {
    if (config.method == "get") {
      config.url = config.url + "?chche=" + Math.random()
    };
    return config;
  },
  err => {
    return Promise.reject(err)
  }
)
export default {
  test (data) {
    return request({
      url: `ceshi`,
      method: 'post',
      data: data
    })
  },
  getToken () {
    return request({
      url: `getToken`,
      method: 'get'
    })
  },
  getTime (cookie) {
    return request({
      url: `getTime`,
      method: 'get',
      params: {
        $cookie: cookie
      }
    })
  },
  getSMS (data, cookie) {
    return request({
      url: `getSMS`,
      method: 'post',
      data: data,
      params: {
        $cookie: cookie
      }
    })
  },
  sendSMS (data, cookie) {
    return request({
      url: `sendSMS`,
      method: 'post',
      data: data,
      params: {
        $cookie: cookie
      }
    })
  },
  login (data, cookie) {
    return request({
      url: `login`,
      method: 'post',
      data: data,
      params: {
        $cookie: cookie
      }
    })
  },
  getUserData (cookie) {
    return request({
      url: `getUserData`,
      method: 'post',
      params: {
        $cookie: cookie
      }
    })
  }
}


