import 'es6-promise/auto'
import Vue from 'vue'
import Vuex from 'vuex'
Vue.use(Vuex)
const store = new Vuex.Store({
  state: {
    account: "",
    name: "",
    team: "",
    coupon: "",
    HP: "",
    LP: ""
  },
  mutations: {
    update (state, data) {
      for (let key in data) {
        state[key] = data[key];
      };
    }
  }
})
export default store


