<template>
  <div class="page">
    <div class="header">
      <div class="title">
        创造与魔法玩家团队
      </div>
      <div class="info">
        <div class="item">
          点券：{{$store.state.coupon}}
        </div>
        <div class="item">
          高威：{{$store.state.HP}}
        </div>
        <div class="item">
          低威：{{$store.state.LP}}
        </div>
      </div>
    </div>
    <div class="content">
      <router-view />
    </div>
    <div class="menu">
      <div class="menu-item" v-bind:class="{active:$route.path=='/main'}" @click="target('/main')">
        <span>
          <i class="el-icon-s-custom"></i>
          首 页
        </span>
      </div>
      <div class="menu-item" v-bind:class="{active:$route.path=='/log'}" @click="target('/log')">
        <span>
          <i class="el-icon-s-order"></i>
          记 录
        </span>
      </div>
      <div class="menu-item" v-bind:class="{active:$route.path=='/list'}" @click="target('/list')">
        <span>
          <i class="el-icon-star-on"></i>
          道 具
        </span>
      </div>
    </div>
  </div>
</template>
<script>
import api from '@/api'
export default {
  name: 'index',
  data () {
    return {
      
    }
  },
  mounted () {
    let userData = this.$script.getCode("userData");
    if (userData.flag) {
      userData.flag = false;
      this.$script.setCode("userData", userData);
    } else {
      api.getUserData(userData.cookie).then((res) => {
        if (res.data.code == 1) {
          this.$store.commit('update', {
            account: userData.username.replace(/(\d{3})\d{4}(\d{4})/, '$1****$2'),
            name: res.data.name,
            team: res.data.team,
            coupon: res.data.coupon,
            HP: res.data.HP,
            LP: res.data.LP
          });
        } else {
          this.$router.push("/login");
        };
      });
    };
  },
  methods: {
    target (path) {
      if (this.$route.path != path) {
        this.$router.push(path);
      }
    }
  }
}
</script>
<style scoped>
.header {
  position: absolute;
  height: 80px;
  width: 100%;
  background-color: rgba(0, 0, 0, 0.75);
  color: #eee;
}

.header .title {
  height: 50px;
  line-height: 50px;
  text-align: center;
  letter-spacing: 0.1em;
  font-size: 20px;
  font-weight: 900;
}

.header .info {
  height: 30px;
  width: 100%;
}

.header .info .item {
  height: 30px;
  line-height: 30px;
  float: left;
}

.header .info .item:nth-child(1) {
  width: 40%;
  text-indent: 0.5em;
}

.header .info .item:nth-child(2) {
  width: 30%;
}

.header .info .item:nth-child(3) {
  width: 30%;
}

.menu {
  position: absolute;
  bottom: 0;
  width: 100%;
  height: 60px;
  background-color: rgba(0, 0, 0, 0.75);
}

.menu .menu-item {
  width: 30%;
  text-align: center;
  color: #eee;
  float: left;
  height: 60px;
  line-height: 60px;
  font-weight: 900;
  font-size: 18px;
}

.menu .menu-item:nth-child(1) {
  margin-left: 5%;
}

.menu .menu-item.active span {
  padding-left: 0.2em;
  padding-right: 0.3em;
  border-bottom: 2px solid #eee;
}

.content {
  position: absolute;
  top: 80px;
  width: 100%;
  bottom: 60px;
}
</style>


