<template>
  <div class='page'>
    <div class="item">
      玩家昵称：{{$store.state.name}}
    </div>
    <div class="item">
      登录账号：{{$store.state.account}}
    </div>
    <div class="item">
      所在团队：{{$store.state.team}}
    </div>
    <div class="item">
      点券余额：{{$store.state.coupon}}
    </div>
    <div class="item">
      高级威望：{{$store.state.HP}}
    </div>
    <div class="item">
      低级威望：{{$store.state.LP}}
    </div>
    <div class="btn">
      <el-button size="small" @click="drawCoupon" disabled>提取点券</el-button>
      <el-button size="small" @click="changePassword" disabled>修改密码</el-button>
      <el-button size="small" @click="logout">退出登录</el-button>
    </div>
  </div>
</template>
<script>
export default {
  data () {
    return {

    };
  },
  mounted () {

  },
  methods: {
    drawCoupon () {

    },
    changePassword () {

    },
    logout () {
      this.$confirm('退出并清除登录信息', '退出确认', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning',
        showClose: false,
        closeOnClickModal: false,
        closeOnPressEscape: false
      }).then(() => {
        this.$script.setCode("userData", {});
        this.$router.push("/login");
      }).catch(() => {});
    }
  }
}
</script>
<style scoped>
.item {
  width: 90%;
  margin-left: 5%;
  height: 40px;
  line-height: 40px;
  border-bottom: 1px solid rgba(0, 0, 0, 0.1);
  overflow: hidden;
  color: #333;
}

.btn {
  text-align: center;
  margin-top: 1em;
}

.el-button {
  margin-bottom: 1em;
}
</style>


