<template>
  <div class='page' v-loading="loading">
    <div class="box">
      <div class="title">
        创造与魔法玩家团队
      </div>
      <div class="item">
        <div class="label">
          账号：
        </div>
        <div class="value">
          <el-input v-model="username" placeholder="请输入账号"></el-input>
        </div>
      </div>
      <div class="item">
        <div class="label">
          密码：
        </div>
        <div class="value">
          <el-input v-model="password" placeholder="请输入密码" show-password></el-input>
        </div>
      </div>
      <div class="item">
        <div class="btn">
          <el-checkbox v-model="remember" @change="setRemember">记住密码</el-checkbox>
          <el-checkbox v-model="autoLogin" @change="setAutoLogin">自动登录</el-checkbox>
          <el-button type="primary" size="small" @click="btn">登 录</el-button>
        </div>
      </div>
    </div>
  </div>
</template>
<script>
import api from '@/api'
export default {
  data () {
    return {
      loading: true,
      username: "",
      password: "",
      remember: false,
      autoLogin: false,
      token: "",
      cookie: "",
      time: ""
    };
  },
  mounted () {
    if (document.body.clientHeight < document.body.clientWidth) {
      this.$alert('PC或PAD请访问原网站', '系统提示', {
        confirmButtonText: '确定',
        callback: action => {
          window.location = "http://czymfgame-230.yingxiong.com/Account/login";
        }
      });
    } else {
      let userData = this.$script.getCode("userData");
      this.username = userData.username || "";
      this.remember = userData.remember || false;
      this.password = this.remember ? userData.password : "";
      this.autoLogin = userData.autoLogin || false;
      this.cookie = userData.cookie || "";
      if (this.cookie == "") {
        this.getToken();
      } else {
        this.getUserData();
      };
    };
  },
  methods: {
    getUserData () {
      api.getUserData(this.cookie).then((res) => {
        if (res.data.code == 1) {
          let userData = {
            username: this.username,
            remember: this.remember,
            password: this.remember ? this.password : "",
            autoLogin: this.autoLogin,
            cookie: this.cookie,
            flag: true
          };
          this.$store.commit('update', {
            account: this.username.replace(/(\d{3})\d{4}(\d{4})/, '$1****$2'),
            name: res.data.name,
            team: res.data.team,
            coupon: res.data.coupon,
            HP: res.data.HP,
            LP: res.data.LP
          });
          this.$script.setCode("userData", userData);
          this.$router.push("/index");
        } else {
          this.getToken();
        };
      });
    },
    getToken () {
      api.getToken(this.cookie).then((res) => {
        this.cookie = res.data.cookie;
        this.token = res.data.token;
        if (this.autoLogin) {
          this.btn();
        } else {
          this.loading = false;
        };
      });
    },
    btn () {
      if (this.cookie == "") {
        this.$message("请稍后重试");
        return;
      };
      if (this.username == "") {
        this.$message("请输入账号");
        return;
      };
      if (this.password == "") {
        this.$message("请输入密码");
        return;
      };
      this.loading = true;
      this.getSMS();
    },
    getSMS () {
      api.getTime(this.cookie).then((res) => {
        this.time = res.data;
        let form = {
          userName: this.username,
          sign: this.$script.BuilderSign('2', this.time, 'userName=' + this.username),
          timestamp: this.time
        };
        api.getSMS(form, this.cookie).then((res) => {
          if (res.data.msg * 1 == res.data.msg) {
            this.login(res.data.msg);
          } else {
            this.sendSMS();
          };
        });
      });
    },
    sendSMS () {
      let form = {
        id: this.username,
        sign: this.$script.BuilderSign('2', this.time, 'id=' + this.username),
        timestamp: this.time
      };
      api.sendSMS(form, this.cookie).then((res) => {
        if (res.data.msg == "短信已发送" || res.data.msg == "验证码还在有效期内，请勿重复发送") {
          this.getSMS();
        } else if (res.data.msg == "用户信息不存在") {
          this.loading = false;
          this.loginText = "账号不存在";
        } else {
          this.loading = false;
          this.loginText = "登录失败：验证码";
        };
      });
    },
    login (SMS) {
      let form = {
        username: this.username,
        password: this.password,
        SMS: SMS,
        token: this.token
      };
      api.login(form, this.cookie).then((res) => {
        if (res.data.code == 0) {
          this.loading = false;
          this.$message(res.data.message);
        } else if (res.data.code == 1) {
          this.cookie = res.data.cookie;
          this.getUserData();
        };
      });
    },
    setAutoLogin () {
      if (this.autoLogin) {
        this.remember = true;
      };
    },
    setRemember () {
      if (!this.remember) {
        this.autoLogin = false;
      };
    }
  }
}
</script>
<style scoped>
.page {
  background: url(../assets/img/login.jpg) no-repeat center/100% 100%;
}

.box {
  position: absolute;
  width: 100%;
  height: 220px;
  top: 28%;
  background-color: rgba(0, 0, 0, 0.75);
  border-radius: 8px;
}

.title {
  width: 100%;
  height: 50px;
  line-height: 50px;
  color: #eee;
  text-align: center;
  font-size: 20px;
  letter-spacing: 0.25em;
  font-weight: 900;
}

.item {
  width: 100%;
  height: 50px;
}

.label {
  float: left;
  width: 25%;
  text-align: right;
  color: #eee;
  line-height: 50px;
}

.value {
  float: left;
  width: 65%;
  height: 40px;
}

.value .el-input {
  width: 100%;
  margin-top: 6px;
  background-color: transparent;
  border-bottom: 1px solid #fff;
}

.value .el-input /deep/ input {
  color: #fff;
  background-color: transparent;
  border: none;
}

.btn {
  float: right;
  margin-top: 15px;
  margin-right: 10%;
}

.el-checkbox {
  color: #eee;
  margin-right: 0.5em;
}

.el-button /deep/ span {
  font-size: 14px;
}
</style>


