import md5 from 'js-md5';
const k = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
const t = 0; // 0=localStorage 1=cookie
// 处理兼容IE--开始
(function (window) {
  try {
    new MouseEvent('test');
    return false;
  } catch (e) {
    // Need to polyfill - fall through
  };
  var MouseEventPolyfill = function (eventType, params) {
    params = params || { bubbles: false, cancelable: false };
    var mouseEvent = document.createEvent('MouseEvent');
    mouseEvent.initMouseEvent(eventType,
      params.bubbles,
      params.cancelable,
      window,
      0,
      params.screenX || 0,
      params.screenY || 0,
      params.clientX || 0,
      params.clientY || 0,
      params.ctrlKey || false,
      params.altKey || false,
      params.shiftKey || false,
      params.metaKey || false,
      params.button || 0,
      params.relatedTarget || null
    );
    return mouseEvent;
  };
  MouseEventPolyfill.prototype = Event.prototype;
  window.MouseEvent = MouseEventPolyfill;
})(window);
// 处理兼容IE--结束
export default {
  setCode: (n, v) => {
    if (typeof v != "string") {
      v = JSON.stringify(v);
    };
    let l = k.length;
    let a = k.split("");
    let s = "", b, b1, b2, b3;
    for (let i = 0; i < v.length; i++) {
      b = v.charCodeAt(i);
      b1 = b % l;
      b = (b - b1) / l;
      b2 = b % l;
      b = (b - b2) / l;
      b3 = b % l;
      s += a[b3] + a[b2] + a[b1];
    };
    if (t == 0) {
      localStorage.setItem(md5(n), s);
    } else if (t == 1) {
      document.cookie = md5(n) + "=" + s;
    };
  },
  getCode: (n) => {
    let v = "";
    if (t == 0) {
      v = localStorage.getItem(md5(n));
    } else if (t == 1) {
      let c = document.cookie.split(/=/g);
      for (let i = 0; i < c.length; i++) {
        if (c[i] == md5(n)) {
          v = c[i + 1];
        };
      };
    };
    if (v == "" || v == null) {
      return {};
    };
    let l = k.length;
    let b, b1, b2, b3, d = 0, s;
    s = new Array(Math.floor(v.length / 3));
    b = s.length;
    for (let i = 0; i < b; i++) {
      b1 = k.indexOf(v.charAt(d));
      d++;
      b2 = k.indexOf(v.charAt(d));
      d++;
      b3 = k.indexOf(v.charAt(d));
      d++;
      s[i] = b1 * l * l + b2 * l + b3;
    };
    b = eval("String.fromCharCode(" + s.join(',') + ")");
    return JSON.parse(b);
  },
  BuilderSign(expiry, timestamp, parms) {
		if (parms != '' && parms.length > 0) {
			var parmsArry = parms.split('&').sort(function(s, t) {
				var a = s.toLowerCase();
				var b = t.toLowerCase();
				if (a.startsWith('onlinetimemsg2=') && b.startsWith('onlinetimemsg=')) {
					return 1;
				} else if (a.startsWith('onlinetimemsg=') && b.startsWith('onlinetimemsg2=')) {
					return -1;
				} else {
					if (a < b) return -1;
					if (a > b) return 1;
        };
				return 0;
			});
			var data;
			for (var i = 0; i < parmsArry.length; i++) {
				if (parmsArry[i] != 'sign' && parmsArry[i] != 'timestamp') {
					if (i == 0) {
						data = parmsArry[i];
					} else {
						data = data + '&' + parmsArry[i];
          };
        };
      };
    };
		var sign = 'expiry' + expiry + 'timestamp' + timestamp + data;
		return md5(sign);
	},
};


